namespace SideSeat.Models.ViewModels;

public class AutocompleteLookupViewModel
{
    public string Name { get; set; } = string.Empty;
    public string Label { get; set; } = string.Empty;
    public string Endpoint { get; set; } = string.Empty;
    public string SelectedId { get; set; } = string.Empty;
    public string SelectedText { get; set; } = string.Empty;
    public string Placeholder { get; set; } = "Pretrazi...";
    public string? HelpText { get; set; }
    public int MinimumLength { get; set; } = 2;
    public bool Required { get; set; }
}

@model SideSeat.Models.ViewModels.AutocompleteLookupViewModel
@{
    var inputId = $"{Model.Name}-lookup";
    var menuId = $"{Model.Name}-menu";
}

<div class="ss-autocomplete" data-ss-autocomplete data-endpoint="@Model.Endpoint" data-min-length="@Model.MinimumLength">
    <label class="form-label" for="@inputId">@Model.Label</label>
    <input type="hidden" name="@Model.Name" value="@Model.SelectedId" data-ss-autocomplete-id />
    <input id="@inputId"
           type="text"
           class="form-control"
           value="@Model.SelectedText"
           placeholder="@Model.Placeholder"
           autocomplete="off"
           data-ss-autocomplete-input
           aria-autocomplete="list"
           aria-controls="@menuId"
           @(Model.Required ? "required" : null) />
    <div id="@menuId" class="ss-autocomplete-menu" data-ss-autocomplete-menu hidden></div>
    @if (!string.IsNullOrWhiteSpace(Model.HelpText))
    {
        <small class="text-muted">@Model.HelpText</small>
    }
</div>

